<?php include __DIR__.'/_init.php';
if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf($_POST['csrf_token']??''))die('CSRF');
if(($_POST['action']??'')==='toggle'){$db->prepare("UPDATE courses SET status=IF(status='published','draft','published') WHERE id=?")->execute([(int)$_POST['id']]);}
else {$db->prepare('INSERT INTO courses(title,slug,short_description,full_description,instructor_name,duration,level,category,price,discounted_price,status,certificate_available,quiz_enabled,meta_title,meta_description,created_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW())')->execute([sanitize($_POST['title']),sanitize($_POST['slug']),sanitize($_POST['short_description']),sanitize($_POST['full_description']),sanitize($_POST['instructor_name']),sanitize($_POST['duration']),sanitize($_POST['level']),sanitize($_POST['category']),(float)$_POST['price'],(float)$_POST['discounted_price'],sanitize($_POST['status']),isset($_POST['certificate_available'])?1:0,isset($_POST['quiz_enabled'])?1:0,sanitize($_POST['meta_title']),sanitize($_POST['meta_description'])]);}
redirect('/admin/courses.php');}
$rows=$db->query('SELECT * FROM courses ORDER BY id DESC')->fetchAll(); ?><h2>Courses</h2><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input name="title" placeholder="Title" required><input name="slug" placeholder="slug" required><input name="short_description" placeholder="short"><textarea name="full_description"></textarea><input name="instructor_name" placeholder="Instructor"><input name="duration" placeholder="8 weeks"><select name="level"><option>Beginner</option><option>Intermediate</option><option>Advanced</option></select><input name="category" placeholder="Category"><input name="price" placeholder="9999"><input name="discounted_price" placeholder="6999"><select name="status"><option>published</option><option>draft</option></select><label><input type="checkbox" name="certificate_available" checked> Certificate</label><label><input type="checkbox" name="quiz_enabled" checked> Quiz</label><input name="meta_title" placeholder="SEO Title"><input name="meta_description" placeholder="SEO Description"><button>Add Course</button></form><table border="1"><tr><th>Title</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['title'])?></td><td><?=e($r['status'])?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?=$r['id']?>"><button>Toggle Publish</button></form></td></tr><?php endforeach;?></table>
